export const localSubjects: Subject[] = rawSubjects.map(({ id, name, teacher_name, description }) => ({
  id,
  name,
  teacher_name,
  description,
  guided_mode_password: '',
  created_at: createdAt,
}));

export const localQuestions: QuestionWithOptions[] = rawSubjects.flatMap(subject =>
  subject.questions.map(([number, text, correct, options]) => {
    const questionId = `${subject.id}-q-${String(number).padStart(2, '0')}`;
    return {
      id: questionId,
      subject_id: subject.id,
      question_number: number,
      question_text: text,
      correct_answer: correct,
      is_exam_question: false,
      created_at: createdAt,
      options: options.map((optionText, index) => {
        const letter = String.fromCharCode(97 + index);
        return {
          id: `${questionId}-${letter}`,
          question_id: questionId,
          letter,
          option_text: optionText,
        };
      }),
    };
  })
);

export function isLocalSubject(subjectId: string) {
  return localSubjects.some(subject => subject.id === subjectId);
}

export function getLocalQuestions(subjectId: string) {
  return localQuestions.filter(question => question.subject_id === subjectId);
}
